package org.apache.commons.csv;

import org.junit.jupiter.api.Test;

import static org.junit.jupiter.api.Assertions.assertEquals;

public class CSVFormatTest {

    @Test
    public void testGetEscapeCharacter() {
        // Given
        Character escapeCharacter = 'E'; // Example escape character for testing
        CSVFormat csvFormat = new CSVFormat(',', '"', null, null, escapeCharacter, false, true, "\r\n",
                null, null, null, false, false, false, false, false);

        // When
        Character result = null;
        try {
            result = (Character) csvFormat.getClass().getDeclaredMethod("getEscapeCharacter").invoke(csvFormat);
        } catch (Exception e) {
            e.printStackTrace();
        }

        // Then
        assertEquals(escapeCharacter, result);
    }

}
